// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWCidade-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&UfeCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "UF") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&UfeCod) EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CIDNOM' &CidNom1.FromString(&GridStateDynamicFilter.Value) If not &CidNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom1) EndIf Case &DynamicFiltersSelector1 = !'CIDCOD' &CidCod1.FromString(&GridStateDynamicFilter.Value) If not &CidCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod1 EndIf Case &DynamicFiltersSelector1 = !'CIDIBGE' &CidIBGE1.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.IBGE" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidIBGE1 EndIf Case &DynamicFiltersSelector1 = !'PAICOD' &PaiCod1.FromString(&GridStateDynamicFilter.Value) If not &PaiCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código País" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PaiCod1 EndIf Case &DynamicFiltersSelector1 = !'CIDARECOD' &CidAreCod1.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Área" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidAreCod1 EndIf Case &DynamicFiltersSelector1 = !'CIDTRACOD' &CidTraCod1.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidTraCod1 EndIf Case &DynamicFiltersSelector1 = !'CIDTRARAZ' &CidTraRaz1.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidTraRaz1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CIDNOM' &CidNom2.FromString(&GridStateDynamicFilter.Value) If not &CidNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom2) EndIf Case &DynamicFiltersSelector2 = !'CIDCOD' &CidCod2.FromString(&GridStateDynamicFilter.Value) If not &CidCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod2 EndIf Case &DynamicFiltersSelector2 = !'CIDIBGE' &CidIBGE2.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.IBGE" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidIBGE2 EndIf Case &DynamicFiltersSelector2 = !'PAICOD' &PaiCod2.FromString(&GridStateDynamicFilter.Value) If not &PaiCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código País" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PaiCod2 EndIf Case &DynamicFiltersSelector2 = !'CIDARECOD' &CidAreCod2.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Área" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidAreCod2 EndIf Case &DynamicFiltersSelector2 = !'CIDTRACOD' &CidTraCod2.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidTraCod2 EndIf Case &DynamicFiltersSelector2 = !'CIDTRARAZ' &CidTraRaz2.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidTraRaz2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CIDNOM' &CidNom3.FromString(&GridStateDynamicFilter.Value) If not &CidNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidNom3) EndIf Case &DynamicFiltersSelector3 = !'CIDCOD' &CidCod3.FromString(&GridStateDynamicFilter.Value) If not &CidCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidCod3 EndIf Case &DynamicFiltersSelector3 = !'CIDIBGE' &CidIBGE3.FromString(&GridStateDynamicFilter.Value) If not &CidIBGE3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.IBGE" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidIBGE3 EndIf Case &DynamicFiltersSelector3 = !'PAICOD' &PaiCod3.FromString(&GridStateDynamicFilter.Value) If not &PaiCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código País" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PaiCod3 EndIf Case &DynamicFiltersSelector3 = !'CIDARECOD' &CidAreCod3.FromString(&GridStateDynamicFilter.Value) If not &CidAreCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Código Área" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidAreCod3 EndIf Case &DynamicFiltersSelector3 = !'CIDTRACOD' &CidTraCod3.FromString(&GridStateDynamicFilter.Value) If not &CidTraCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Cód.Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CidTraCod3 EndIf Case &DynamicFiltersSelector3 = !'CIDTRARAZ' &CidTraRaz3.FromString(&GridStateDynamicFilter.Value) If not &CidTraRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Transp." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CidTraRaz3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cidade" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "IBGE" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "UF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Estado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "País" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "País Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Área Vendas" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Transp."
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each Cidade order EmpCod CidNom when &OrderedBy = 1 order CidCod when &OrderedBy = 2 AND &OrderedDsc = False order (CidCod) when &OrderedBy = 2 AND &OrderedDsc = True order CidNom when &OrderedBy = 3 AND &OrderedDsc = False order (CidNom) when &OrderedBy = 3 AND &OrderedDsc = True order CidIBGE when &OrderedBy = 4 AND &OrderedDsc = False order (CidIBGE) when &OrderedBy = 4 AND &OrderedDsc = True order UfeCod when &OrderedBy = 5 AND &OrderedDsc = False order (UfeCod) when &OrderedBy = 5 AND &OrderedDsc = True order UfeNom when &OrderedBy = 6 AND &OrderedDsc = False order (UfeNom) when &OrderedBy = 6 AND &OrderedDsc = True order PaiCod when &OrderedBy = 7 AND &OrderedDsc = False order (PaiCod) when &OrderedBy = 7 AND &OrderedDsc = True order PaiNom when &OrderedBy = 8 AND &OrderedDsc = False order (PaiNom) when &OrderedBy = 8 AND &OrderedDsc = True order CidAreCodNom when &OrderedBy = 9 AND &OrderedDsc = False order (CidAreCodNom) when &OrderedBy = 9 AND &OrderedDsc = True
Where UfeCod Like &UfeCod when not &UfeCod.IsEmpty() Where CidNom like &CidNom1 when &DynamicFiltersSelector1 = !'CIDNOM' AND (not &CidNom1.IsEmpty()) Where CidCod = &CidCod1 when &DynamicFiltersSelector1 = !'CIDCOD' AND (not &CidCod1.IsEmpty()) Where CidIBGE = &CidIBGE1 when &DynamicFiltersSelector1 = !'CIDIBGE' AND (not &CidIBGE1.IsEmpty()) Where PaiCod = &PaiCod1 when &DynamicFiltersSelector1 = !'PAICOD' AND (not &PaiCod1.IsEmpty()) Where CidAreCod = &CidAreCod1 when &DynamicFiltersSelector1 = !'CIDARECOD' AND (not &CidAreCod1.IsEmpty()) Where CidTraCod = &CidTraCod1 when &DynamicFiltersSelector1 = !'CIDTRACOD' AND (not &CidTraCod1.IsEmpty()) Where CidTraRaz like &CidTraRaz1 when &DynamicFiltersSelector1 = !'CIDTRARAZ' AND (not &CidTraRaz1.IsEmpty()) Where CidNom like &CidNom2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDNOM' AND (not &CidNom2.IsEmpty()) Where CidCod = &CidCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDCOD' AND (not &CidCod2.IsEmpty()) Where CidIBGE = &CidIBGE2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDIBGE' AND (not &CidIBGE2.IsEmpty()) Where PaiCod = &PaiCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'PAICOD' AND (not &PaiCod2.IsEmpty()) Where CidAreCod = &CidAreCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDARECOD' AND (not &CidAreCod2.IsEmpty()) Where CidTraCod = &CidTraCod2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDTRACOD' AND (not &CidTraCod2.IsEmpty()) Where CidTraRaz like &CidTraRaz2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'CIDTRARAZ' AND (not &CidTraRaz2.IsEmpty()) Where CidNom like &CidNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDNOM' AND (not &CidNom3.IsEmpty()) Where CidCod = &CidCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDCOD' AND (not &CidCod3.IsEmpty()) Where CidIBGE = &CidIBGE3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDIBGE' AND (not &CidIBGE3.IsEmpty()) Where PaiCod = &PaiCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'PAICOD' AND (not &PaiCod3.IsEmpty()) Where CidAreCod = &CidAreCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDARECOD' AND (not &CidAreCod3.IsEmpty()) Where CidTraCod = &CidTraCod3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDTRACOD' AND (not &CidTraCod3.IsEmpty()) Where CidTraRaz like &CidTraRaz3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'CIDTRARAZ' AND (not &CidTraRaz3.IsEmpty()) Where EmpCod = ProcRetCompany.Udp()
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CidCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(CidNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = CidIBGE &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(UfeCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(UfeNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = PaiCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(PaiNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = WWP_Export_SecureText(CidAreCodNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(CidTraCodRaz)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCidadeGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCidadeGridState")) Else &GridState.FromXml(&Session.Get(!"WWCidadeGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"UFECOD" &UfeCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
